import {
  successResponse,
  fromNeverthrowError,
  outputAndExit,
} from '@/cli/output';

import { submitErrorReport } from '@/operations/report-error';
import { getWalletOrExit } from '../lib/get-wallet-or-exit';

import type { Command } from '@/types';
import type { ErrorReportInput } from '@/operations/report-error';

const SURFACE = 'cli:report-error';

export const reportErrorCommand: Command<ErrorReportInput> = async args => {
  const {
    evm: { address },
  } = await getWalletOrExit(args);

  const result = await submitErrorReport(SURFACE, args, address, args.dev);

  if (result.isErr()) {
    return outputAndExit(fromNeverthrowError(result), args);
  }

  return outputAndExit(successResponse(result.value), args);
};
